import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  // ✅ state
  const [index, setIndex] = useState(0);
  const [selectedImage, setSelectedImage] = useState(null);

  // ✅ تغيير النص كل 2 ثواني
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  // ✅ بيانات الصور الثلاث
  const images = [
    {
      id: 1,
      url: "https://placehold.co/800x600/2c3e50/ffffff?text=QR+Code",
      title: "رمز QR",
      description: "مسح سريع وطلب مباشر للمطبخ"
    },
    {
      id: 2,
      url: "https://placehold.co/800x600/34495e/ffffff?text=Waiter+Orders",
      title: "العامل والطلبات",
      description: "إدارة الطلبات وتحديد مكان الطاولة وعرض الأسعار"
    },
    {
      id: 3,
      url: "https://placehold.co/800x600/16a085/ffffff?text=Smart+Invoice",
      title: "الفاتورة الذكية",
      description: "حساب المجموع الكلي مع الضريبة وتفاصيل كل طلب"
    }
  ];

  const openModal = (image) => {
    setSelectedImage(image);
    document.body.style.overflow = "hidden";
  };

  const closeModal = () => {
    setSelectedImage(null);
    document.body.style.overflow = "auto";
  };

  return (
    <>
      <Navbar transparent />
      <main>
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen">
          {/* ✅ هنا الصور الثلاث جنب بعضهم بالعرض - نفس مكان الصورة القديمة */}
          <div className="absolute top-0 w-full h-full">
            <div className="w-full h-full flex">
              {images.map((image) => (
                <div
                  key={image.id}
                  className="flex-1 relative overflow-hidden cursor-pointer group"
                  onClick={() => openModal(image)}
                >
                  <img
                    src={image.url}
                    alt={image.title}
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                  />
                  {/* طبقة شفافة داكنة لتحسين وضوح النص */}
                  <div className="absolute inset-0 bg-black bg-opacity-40 group-hover:bg-opacity-30 transition-all duration-300"></div>
                  {/* عنوان الصورة عند التمرير */}
                  <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black to-transparent p-6 translate-y-full group-hover:translate-y-0 transition-transform duration-300">
                    <h3 className="text-white text-xl font-bold mb-2">{image.title}</h3>
                    <p className="text-white text-sm opacity-0 group-hover:opacity-100 transition-opacity duration-300 delay-100">
                      اضغط للمزيد
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* ✅ المحتوى فوق الصور */}
          <div className="container relative mx-auto z-10">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-6/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  {/* النص المتغيّر */}
                  <h1
                    key={texts[index]}
                    className="text-white font-semibold text-5xl transition-all duration-500 drop-shadow-lg"
                  >
                    {texts[index]}
                  </h1>

                  <p className="mt-4 text-lg text-blueGray-200 drop-shadow">
                    Welcome to our website
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* باقي الكود كما هو */}
      </main>
      <Footer />

      {/* ✅ مودال عرض الصورة المكبرة */}
      {selectedImage && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-90 backdrop-blur-sm"
          onClick={closeModal}
        >
          <div
            className="relative max-w-4xl w-full bg-white rounded-2xl overflow-hidden shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={closeModal}
              className="absolute top-4 right-4 z-10 bg-black bg-opacity-50 hover:bg-opacity-70 text-white w-10 h-10 rounded-full flex items-center justify-center"
            >
              ✕
            </button>

            <div className="flex flex-col md:flex-row">
              <div className="md:w-1/2 bg-gray-100">
                <img
                  src={selectedImage.url}
                  alt={selectedImage.title}
                  className="w-full h-64 md:h-full object-cover"
                />
              </div>
              <div className="md:w-1/2 p-6 md:p-8">
                <h2 className="text-2xl md:text-3xl font-bold text-gray-800 mb-4">
                  {selectedImage.title}
                </h2>
                <p className="text-gray-600 leading-relaxed mb-4">
                  {selectedImage.description}
                </p>
                <div className="border-t pt-4 mt-4">
                  <p className="text-sm text-gray-500">
                    ✨ هذه إحدى المهام الرئيسية في التطبيق
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
